window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["map"]={"updatedAt":"2026-07-14","count":110,"nodes":[{"id":"vo-bien-hai","name":"Vô Biên Hải","cn":"无边海","capDo":"vuc","parentId":null,"blurb":"Vùng biển rộng lớn phía bắc Thiên Nam, hầu như không có đảo, chỉ có hải thú hung mãnh.","detail":"Vùng biển phía bắc lục địa Thiên Nam, tên do người Thiên Nam đặt vì không ai dò xét hết giới hạn. Đặc điểm: ngư hà rất ít, hải đảo cũng không nhiều, tử khí trầm lắng, chỉ có hải thú hung mãnh, không có yêu thú. Là nơi có Hinh Nha Thú — loài hải thú kỳ lạ không xuất hiện ở Loạn Tinh Hải.","theLucLienQuan":[],"nguon":["@c0593"]},{"id":"khe-quoc","name":"Khê Quốc","cn":"溪国","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Quốc gia nhỏ ở đông bắc Thiên Nam, diện tích bằng khoảng hai phần ba Việt Quốc, chia làm bảy châu phủ.","detail":"Quốc gia thuộc phần đông bắc Thiên Nam, diện tích nhỏ hơn Việt Quốc một chút (bằng khoảng hai phần ba), bị chia làm bảy châu phủ. Tiếp giáp Vô Biên Hải.","theLucLienQuan":[],"nguon":["@c0593","@c0599"]},{"id":"man-chau","name":"Mẫn Châu","cn":"闽州","capDo":"chau","parentId":"khe-quoc","blurb":"Châu lớn nhất trong bảy châu của Khê Quốc, nằm gần Vô Biên Hải.","detail":"Một trong bảy châu của Khê Quốc, nằm gần Vô Biên Hải, là châu lớn nhất. Chủ phủ là Phong Nhật Thành. Nơi ba người Hàn Lập đáp xuống sau khi bay từ Vô Biên Hải về Thiên Nam.","theLucLienQuan":[],"nguon":["@c0593"]},{"id":"phong-nhat-thanh","name":"Phong Nhật Thành","cn":"丰日城","capDo":"thanh","parentId":"man-chau","blurb":"Chủ phủ của Mẫn Châu, thành thị lớn nhất Mẫn Châu.","detail":"Chủ phủ của Mẫn Châu thuộc Khê Quốc, thành thị lớn nhất Mẫn Châu.","theLucLienQuan":[],"nguon":["@c0593"]},{"id":"van-mong-son","name":"Vân Mộng Sơn","capDo":"khac","parentId":"khe-quoc","blurb":"Linh khí thánh mạch nổi danh Thiên Nam, nằm trong Khê Quốc. Sâu trong dãy núi có Linh Nhãn Chi Thụ — một trong ba đại thần mộc cuối cùng.","detail":"Dãy núi linh mạch nổi danh, do Cổ Kiếm Viện, Lạc Vân Tông, Bách Xảo Viện liên hợp chiếm cứ. Sâu bên trong có Linh Nhãn Chi Thụ, mỗi hai trăm năm chảy ra Thuần dịch. Hàn Lập đến đây đúng dịp Lạc Vân Tông thu nhận đệ tử.","theLucLienQuan":["Lạc Vân Tông","Cổ Kiếm Viện","Bách Xảo Viện"],"nguon":["@c0594","@c0644","@c0788"],"cn":"云梦山"},{"id":"huyen-van-duong","name":"Huyễn Vân Đường","cn":"幻云堂","capDo":"khac","parentId":"van-mong-son","blurb":"Tòa bạch ngọc lâu cao hơn mười trượng ẩn sau ảo trận trên đường lên Lạc Vân Tông, treo biển ba chữ vàng, nơi tuyển chọn đệ tử.","detail":"Tòa bạch ngọc lâu lớn cao hơn mười trượng tại Vân Mộng Sơn, ẩn sau ảo trận khiến tán tu chỉ nhìn thấy một tiểu đình. Treo biển ba chữ vàng lấp lánh. Phía trước là sân rộng hơn trăm trượng. Nơi ba tu sĩ Lạc Vân Tông (Thu sư huynh, Lưu sư huynh, thanh niên anh khí) tuyển chọn đệ tử tán tu.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0596"]},{"id":"luc-ky-phong","name":"Lục Kỳ Phong","capDo":"khac","parentId":"van-mong-son","blurb":"Sơn môn chính của Lạc Vân Tông trên Vân Mộng Sơn, phòng ốc điện phủ lầu các san sát, nhiều tu sĩ qua lại.","detail":"Khu vực gồm nhiều ngọn núi với phòng ốc điện phủ lầu các san sát, nơi tu sĩ Lạc Vân Tông với phục sức khác nhau bay tới bay lui. Du sư đệ giới thiệu đây là sơn môn của đệ tử Lạc Vân Tông.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0597"]},{"id":"thien-tuyen-phong","name":"Thiên Tuyền Phong","capDo":"khac","parentId":"van-mong-son","blurb":"Ngọn núi thuộc Lạc Vân Tông, nơi tân đệ tử khai báo lai lịch xuất thân và kiểm tra công pháp tu vi.","detail":"Du sư đệ dẫn nhóm Hàn Lập cùng sáu tu sĩ đạt tiêu chuẩn tới Thiên Tuyền Phong để khai báo lai lịch và kiểm tra công pháp tu vi.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0597"]},{"id":"nghenh-tung-cu","name":"Nghênh Tùng Cư","cn":"","capDo":"khac","parentId":"thien-tuyen-phong","blurb":"Lầu các dưới chân Thiên Tuyền Phong, nơi Miêu sư huynh chờ đoàn tán tu mới để kiểm tra Vấn Tâm Thuật.","detail":"Tầng một là phòng tiếp có ghế thái sư. Tầng hai trống rỗng chỉ có hai bồ đoàn dùng làm nơi kiểm tra Vấn Tâm Thuật.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0598"]},{"id":"tuyen-phong-son","name":"Tuyền Phong Sơn","cn":"泉峰山","capDo":"khac","parentId":"thien-tuyen-phong","blurb":"Ngọn núi nơi Thiên Tuyền Phong đóng đô, có dãy lầu các và sương phòng u tĩnh của sư tổ.","detail":"Tuyền Phong Sơn là nơi đặt căn cứ của Thiên Tuyền Phong. Trên núi có dãy lầu các, sương phòng u tĩnh nơi sư tổ Kết Đan trung kỳ tiếp kiến đệ tử. Hàn Lập và Đỗ Đông được Du Quân dẫn đến đây bái kiến sư tổ dưới danh nghĩa ngoại môn đệ tử mới.","theLucLienQuan":["thien-tuyen-phong"],"nguon":["@c0600"]},{"id":"duoc-vien-mo-phai-linh","name":"Dược viên Mộ Phái Linh","cn":"","capDo":"khac","parentId":"tuyen-phong-son","blurb":"Khu vườn dược liệu rộng hơn trăm trượng phía sau động phủ Mộ Phái Linh, nơi Hàn Lập tiếp quản.","detail":"Dược viên nằm phía sau động phủ của Mộ Phái Linh trên Tuyền Phong Sơn, rộng hơn trăm trượng. Bên trong trồng vài loại dược thảo, có ba tòa nhà tranh và một ngọn núi nhỏ vô danh. Mộ Phái Linh giao nơi đây cho Hàn Lập trông coi, chỉ cần hằng năm giao lên một lượng dược liệu nhất định. Nơi đây chính thức trở thành địa bàn của Hàn Lập.","theLucLienQuan":["thien-tuyen-phong"],"nguon":["@c0600"]},{"id":"tieu-thach-son-dong-phu","name":"Tiểu thạch sơn (động phủ bí mật)","cn":"","capDo":"khac","parentId":"duoc-vien-mo-phai-linh","blurb":"Núi đá nhỏ phía sau dược viên Mộ Phái Linh, nơi Hàn Lập bí mật khai phá động phủ gồm nhiều thạch thất, bên ngoài bố trí trận pháp ẩn nặc cao cấp.","detail":"Hàn Lập dùng mười mấy thanh phi kiếm đào tiểu thạch sơn phía sau dược viên, tạo ra động phủ nhỏ gồm nhiều thạch thất: phòng luyện công, trùng thất, linh thú thất, tiểu dược viên. Bên ngoài bố trí nhiều trận pháp ẩn nặc cao cấp đủ che mắt tu sĩ Kết Đan Kỳ, dự định bổ sung Câu Linh Trận để che cả Nguyên Anh Kỳ.","theLucLienQuan":[],"nguon":["@c0601"]},{"id":"luc-tung-chieu-trach","name":"Lục Tung chiểu trạch","cn":"","aliases":["Đầm lầy Lục Tung"],"capDo":"khac","parentId":"tuyen-phong-son","blurb":"Khu đầm lầy gần nơi Khuê Hoán trông coi linh thú, là nơi sinh sống của Tuyết Vân Hồ thường và dị chủng Tuyết Vân Hồ đã tiến hóa thành yêu thú cấp thấp.","detail":"Khu đầm lầy cách vùng bình nguyên trông coi linh thú không xa. Dị chủng Tuyết Vân Hồ trốn ở chỗ sâu trong đầm, chui vào bùn ẩn thân. Nhóm Khuê Hoán dự định bố trí Mê Tung trận tại đây để vây bắt.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0603"]},{"id":"dam-lay-trung-tam","name":"Đầm lầy (trung tâm)","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực đầm lầy mà nhóm Hàn Lập bay vào để bắt Tuyết Vân Hồ. Trung tâm có khoảng đất bằng phẳng cỏ xanh trải dài, xung quanh có bụi cây nhỏ, có chướng khí tự nhiên.","detail":"Vùng đầm lầy nằm gần khu vực hoạt động của Lạc Vân Tông. Nhóm năm người bay cách mặt đất hơn mười trượng tiến về trung tâm. Trung tâm có khoảng đất cỏ xanh bằng phẳng đủ rộng để bày Ngũ Hành Mê Tung trận. Chướng khí dày đặc, tu sĩ thường cần đan dược khu trừ.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"ngon-nui-da-bien-dam-lay","name":"Ngọn núi đá (biên đầm lầy)","cn":"","capDo":"khac","parentId":"dam-lay-trung-tam","blurb":"Ngọn núi lớn ở vùng biên đầm lầy, vách đá xanh sắc nhọn chót vót. Bên trong có thạch thất bị phong bế bởi lực lượng cổ quái có thể bắn ngược thần thức.","detail":"Ngọn núi đá nằm ở vùng biên đầm lầy, nơi Tuyết Vân Hồ độn thổ trốn vào và Hàn Lập truy đuổi theo bằng Thổ Độn Thuật. Bên trong núi có một thạch thất phong bế, được bảo vệ bởi lực lượng cổ quái có thể bắn ngược thần thức của tu sĩ Trúc Cơ kỳ. Một nhân vật bí ẩn ẩn thân bên trong.","theLucLienQuan":[],"nguon":["@c0606"]},{"id":"thach-that-hap-linh-thach","name":"Thạch thất Hấp Linh thạch","cn":null,"capDo":"khac","parentId":null,"blurb":"Căn phòng đá bí ẩn có vách tường bằng Hấp Linh thạch (Thanh Kim thạch), nơi hắc y thiếu phụ tu vi Nguyên Anh kỳ ẩn tu, nằm trong khu vực mật cảnh ba phái.","detail":"Thạch thất trống trơn, vách tường thô sơ lồi lõm không giống động phủ tu sĩ bình thường, bên trong chỉ có đài đá. Toàn bộ vách tường được tạo từ Thanh Kim thạch (Hấp Linh thạch), loại tài liệu luyện khí cực hiếm gần thất truyền — kiếm mang công kích không để lại vết, phi kiếm chỉ tạo lỗ nhỏ sâu một tấc rồi tự liền lại, miễn dịch linh lực. Hắc y thiếu phụ Nguyên Anh kỳ ẩn tu tại đây, không thể rời khỏi vì nguyên nhân bí ẩn. Thạch thất nằm ngay dưới mắt ba phái mà không ai hay biết.","theLucLienQuan":[],"nguon":["@c0607"]},{"id":"tay-tam-dien","name":"Tẩy Tâm Điện","cn":"洗心殿","capDo":"khac","parentId":"thien-tuyen-phong","blurb":"Điện đường cổ kính trên Thiên Tuyền Phong, nơi thương nghị sự tình và tụ họp chúng đệ tử, biển bạc ghi tên, cửa gỗ lớn.","detail":"Tòa điện đường cổ kính xây dựa vào núi giữa sườn Thiên Tuyền Phong, phía trước có sân rộng. Biển bạc ghi ba chữ lớn Tẩy Tâm Điện. Cửa gỗ lớn chỉ tu sĩ Trúc Cơ kỳ mới được vào bên trong, đệ tử Luyện Khí kỳ tụ tập bên ngoài sân.","theLucLienQuan":["Thiên Tuyền Phong"],"nguon":["@c0617"]},{"id":"van-mong-tay-mach","name":"Vân Mông Tây Mạch","capDo":"vuc","parentId":"van-mong-son","blurb":"Khu vực phía tây Vân Mộng Sơn, thuộc địa bàn Bách Xảo Viện. Địa điểm tổ chức Thí Kiếm đại hội lần này.","detail":"Vân Mông Tây Mạch là phần phía tây của Vân Mộng Sơn, thuộc địa bàn quản lý của Bách Xảo Viện. Được chọn làm nơi tổ chức Thí Kiếm đại hội giữa ba phái.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0618"]},{"id":"dau-truong-luc-xao-phong","name":"Đấu trường Lục Xảo Phong","capDo":"khac","parentId":"van-mong-son","blurb":"Khu đất trống rộng lớn ngay dưới đỉnh núi, nơi tổ chức tỷ thí tuyển chọn đệ tử Lục Xảo Phong.","detail":"Khu đất trống dưới đỉnh núi, đặt ba tòa pháp trận rộng hơn trăm trượng, bao quanh bởi hào quang nửa hình tròn. Ba tu sĩ Trúc Cơ hậu kỳ làm trọng tài, đứng trên không trong màn hào quang giám sát. Hơn bốn năm trăm đệ tử các phong thi đấu tại đây.","theLucLienQuan":["Hoàng Phong Cốc"],"nguon":["@c0619"]},{"id":"bach-phuong-phong","name":"Bạch Phượng Phong","cn":"","capDo":"khac","parentId":"luc-ky-phong","blurb":"Ngọn núi phía cực đông Lạc Vân Tông, nhỏ nhất trong sáu ngọn nhưng cảnh sắc tú lệ đệ nhất, nơi nhiều nữ tu cư trú.","detail":"Nằm cách biệt hẳn so với năm ngọn núi khác của Lục Kỳ Phong. Khắp nơi tràn ngập màu xanh, hoa mộc đầy núi. Nam đệ tử phải thông báo qua đệ tử canh núi mới được vào. Trên đỉnh có mảnh đất bằng phẳng trăm trượng, mây trắng bao phủ, linh khí dư dật, chỉ có tòa Phượng Các. Là nơi ở của Tống sư tổ.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0623"]},{"id":"phuong-cac","name":"Phượng Các","cn":"","capDo":"khac","parentId":"bach-phuong-phong","blurb":"Tòa lầu các ba tầng trên đỉnh Bạch Phượng Phong, nơi ở và tiếp khách của Tống sư tổ.","detail":"Bằng bạch mộc cổ phác không bụi bặm, cao ước hai mươi trượng. Tầng một trống rỗng chỉ có trận pháp luyện công, tầng hai giản khiết có giá gỗ nhỏ chất pháp khí ngọc giản và vài ghế.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0623"]},{"id":"bach-xao-vien-tong-mon","name":"Bách Xảo Viện tông môn","cn":"","capDo":"khac","parentId":"van-mong-son","blurb":"Tông môn Bách Xảo Viện nằm ở núi non phía tây Vân Mộng Sơn.","detail":"Sơn cốc được núi non bao quanh tứ phía, có khoảng sân rộng giữa sơn cốc. Mấy ngàn đệ tử mặc quần áo sặc sỡ tụ tập tại đây.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0623"]},{"id":"dau-truong-thi-kiem","name":"Đấu trường Thí Kiếm Đại Hội","cn":"","capDo":"khac","parentId":"bach-xao-vien-tong-mon","blurb":"Khoảng sân rộng tại Bách Xảo Viện, nơi tổ chức Thí Kiếm Đại Hội ba phái, có đấu tràng vây quang tráo, đủ chứa mấy ngàn đệ tử.","detail":"Khoảng sân rộng bên trong Bách Xảo Viện, nơi tổ chức các trận tỷ thí của Thí Kiếm Đại Hội. Có đấu tràng được quang tráo bao quanh, đủ chứa mấy ngàn đệ tử ba phái đứng xem.","theLucLienQuan":["Bách Xảo Viện","Cổ Kiếm Môn","Lạc Vân Tông"],"nguon":["@c0624"]},{"id":"son-coc-minh-thanh","name":"Sơn cốc Minh Thanh Linh Thủy","cn":"","capDo":"khac","parentId":"van-mong-son","blurb":"Sơn cốc vô danh hẻo lánh trong Vân Mộng Sơn, sương mù dày đặc, đầy bọ cạp rắn và trùng độc, bên trong chứa thánh địa điều chế Minh Thanh Linh Thủy.","detail":"Nơi hẻo lánh quanh năm sương mù dày đặc, đầy bọ cạp, rắn và trùng độc. Bên trong có thánh địa Minh Thanh Linh Thủy liên quan Linh Nhãn Chi Thụ. Cấm chế rất mạnh, ba tu sĩ Kết Đan ngày đêm thủ hộ. Có huyền cơ truyền tống, đệ tử truyền tống đến sẽ không biết nơi này ở đâu.","theLucLienQuan":["Cổ Kiếm Môn","Lạc Vân Tông","Bách Xảo Viện"],"nguon":["@c0625"]},{"id":"tam-phai-cam-dia","name":"Tam Phái Cấm Địa","cn":"","capDo":"khac","parentId":null,"blurb":"Cấm địa chung của ba phái Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo Viện, do Nguyên Anh Kỳ tu sĩ thiết lập cấm chế. Bên trong có thánh thụ (Linh Nhãn Chi Thụ), ba tu sĩ Kết Đan trấn thủ.","detail":"Vị trí hoang vu sương mù dày đặc, không khí ẩm ướt. Thạch bích đầy rêu che cửa đá dày đặc chú văn, nhiều tầng vách cấm chế bảo vệ. Cấm chế do mấy vị sư thúc Nguyên Anh Kỳ ba phái cùng thiết lập, ngăn thần thức chỉ vươn hơn mười trượng. Bên trong có thánh thụ (Linh Nhãn Chi Thụ). Ba tu sĩ Kết Đan (họ Việt, Ngô, Điền) trấn thủ. Bình thường ngay cả Kết Đan cũng không được tới gần. Đệ tử mười năm một lần được vào, chỉ ở một ngày một đêm.","theLucLienQuan":["Cổ Kiếm Môn","Lạc Vân Tông","Bách Xảo Viện"],"nguon":["@c0626"]},{"id":"thach-sanh-co-kiem-mon","name":"Thạch sảnh Cổ Kiếm Môn","cn":"","capDo":"khac","parentId":null,"blurb":"Gian phòng đá rộng năm sáu mươi trượng, cao bảy tám trượng, nằm cuối thông đạo hình vuông dài hơn trăm trượng khoét trong núi. Vách bóng loáng khắc phù chú, bên trong có bàn cờ đá xanh lớn.","detail":"Thông đạo có cấm chế cần lệnh bài và pháp thuật để vượt qua. Nơi đồng tử Lam sư thúc (Nguyên Anh sơ kỳ) và Hồ sư điệt đánh cờ. Xảy ra sự kiện nho sinh bị lật tẩy và chế phục.","theLucLienQuan":["Cổ Kiếm Môn"],"nguon":["@c0627"]},{"id":"hang-dong-linh-nhan-chi-thu","name":"Hang động Linh Nhãn Chi Thụ","cn":"","capDo":"khac","parentId":"tam-phai-cam-dia","blurb":"Hang động chung nhũ rộng vài trăm trượng, cao hai ba mươi trượng, nằm sau cánh cửa đá vàng xỉn. Bên trong có rừng trụ đá thạch nhũ tạo mê cung, trung tâm là Linh Nhãn Chi Thụ — nguồn linh khí tinh thuần cao hơn cả Linh Nhãn Chi Ngọc.","detail":"Thánh địa nằm sâu trong Tam Phái Cấm Địa, được Vệ sư huynh (Kết Đan kỳ) canh giữ. Cửa vào là cánh cửa đá màu vàng xỉn có cấm chế. Bên trong dưới mặt đất có lớp linh quang trắng bị cấm chế phong ấn. Rừng trụ đá thạch nhũ tạo mê cung, phải dùng pháp khí (kính nhỏ trắng) phát ánh sáng mới tách trụ đá mở đường. Trung tâm thạch lâm đặt Linh Nhãn Chi Thụ với hào quang vàng bảo vệ, dưới gốc có bình ngọc chứa hương dược phối chế Minh Thanh Linh Thủy.","theLucLienQuan":["Lạc Vân Tông","Bách Xảo Viện","Cổ Kiếm Môn"],"nguon":["@c0628"]},{"id":"mo-lan-thao-nguyen","name":"Mộ Lan thảo nguyên","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Vùng thảo nguyên gần nơi chánh tà hai phái phát hiện Huyền Thiên Tiên Đằng thượng cổ đã héo.","detail":"Chánh tà hai phái phát hiện một gốc cây thượng cổ tên Huyền Thiên Tiên Đằng tại vùng phụ cận Mộ Lan thảo nguyên, cây đã héo rũ, cần thuần dịch Linh Nhãn Chi Thụ để cứu.","theLucLienQuan":["Thiên Sát Tông"],"nguon":["@c0630"]},{"id":"dong-quat-linh-nhan","name":"Động quật Linh Nhãn Chi Thụ","cn":"","capDo":"khac","parentId":"hang-dong-linh-nhan-chi-thu","blurb":"Động quật chứa Linh Nhãn Chi Thụ bên trong quang tráo kim sắc, có cửa đá ra vào và cấm chế bảo hộ.","detail":"Bên trong có quang tráo kim sắc bảo hộ Linh Nhãn Chi Thụ, cạnh linh thụ có bồ đoàn vàng và ngọc giản lục quang. Cửa đá là lối ra vào chính. Vách tường bị Thiên Sát Chân Quân đánh vỡ tạo lỗ hổng. Cấm chế bên ngoài đã bị lão giả mặt dài phá hoại, uy lực chỉ còn một phần mười.","theLucLienQuan":["Vân Mộng Sơn","Lạc Vân Tông"],"nguon":["@c0632"]},{"id":"dong-phu-tieu-son-thach","name":"Động phủ tiểu sơn thạch","capDo":"khac","parentId":"lac-van-tong","blurb":"Động phủ của Hàn Lập tại Lạc Vân Tông, nơi trồng linh căn Linh Nhãn Chi Thụ gần Cửu Khúc Linh Sâm và khổ tu hơn hai mươi năm.","detail":"Nơi Hàn Lập ẩn tu dưới thân phận đệ tử Luyện Khí Kỳ, trồng linh căn Linh Nhãn Chi Thụ gần Cửu Khúc Linh Sâm trong động phủ, dùng lục dịch thúc dục cây con mọc lên, đồng thời tu luyện Đại Diễn Quyết và Thanh Nguyên Kiếm Quyết suốt hơn hai mươi năm.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0633"]},{"id":"chu-phong-lac-van-tong","name":"Chủ phong Lạc Vân Tông","cn":"","capDo":"khac","parentId":"van-mong-son","blurb":"Ngọn núi chính của Lạc Vân Tông, nơi Trình sư huynh (Nguyên Anh kỳ) tu luyện. Có động phủ cao mấy ngàn trượng và khối cự thạch cao lớn trên đỉnh.","detail":"Chủ phong là ngọn núi chính của Lạc Vân Tông tại Vân Mộng Sơn. Trên đỉnh có khối cự thạch cao lớn, Trình sư huynh đứng trên đó quan sát dị tượng kết anh. Động phủ Nguyên Anh nằm ở vị trí cao mấy ngàn trượng.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0635"]},{"id":"dong-phu-han-lap-van-mong-son","name":"Động phủ Hàn Lập (Vân Mộng Sơn)","cn":"","capDo":"khac","parentId":"van-mong-son","blurb":"Ngọn núi phía đông Lạc Vân Tông mà Hàn Lập chọn lập động phủ, gồm một chủ phong với ba tòa núi thấp bao quanh, được bố trí trận pháp sương mù bao phủ phương viên hơn mười dặm.","detail":"Nằm trên đông mạch Vân Mộng Sơn thuộc lãnh thổ Lạc Vân Tông. Một chủ phong với ba tòa núi thấp bốn phía, thích hợp bố trí cấm pháp trận. Hàn Lập khai mở động phủ trong nửa ngày, bày trận pháp tạm thời tạo sương mù bao phủ hơn mười dặm, dự tính sau sẽ thay bằng cấm chế mạnh hơn khi ngộ ra trận pháp chi đạo cao hơn.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0639"]},{"id":"dong-phu-nui-da-lac-van-tong","name":"Động phủ trong núi đá (dược viên + trùng thất)","cn":"","capDo":"khac","parentId":"chu-phong-lac-van-tong","blurb":"Động phủ cũ của Hàn Lập tại Lạc Vân Tông, chứa dược viên trồng Linh Nhãn Chi Thụ, Cửu Khúc Linh Sâm và trùng thất nuôi Phệ Kim Trùng.","detail":"Nằm trong núi đá thuộc khu vực chủ phong Lạc Vân Tông. Bên trong có trùng thất chứa gần vạn con xích kim Phệ Kim Trùng và dược viên trồng nhiều loại linh dược. Sau khi Hàn Lập di chuyển linh trùng và linh dược quý về tân động phủ, chỉ còn bảy tám loại tạp linh dược bỏ lại.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0640"]},{"id":"tan-dong-phu-han-lap","name":"Tân động phủ Hàn Lập","cn":"","capDo":"khac","parentId":null,"blurb":"Ngọn núi mới Hàn Lập khai mở làm động phủ, có cấm chế mê vụ bao quanh và tử phong che phủ bên ngoài.","detail":"Hàn Lập khai phá tân động phủ tại ngọn núi mới, bên ngoài là tử phong bao quanh có cấm chế mê vụ, bên trong có tĩnh thất nơi hắn ngưng luyện nguyên anh trăm ngày. Mộ Phái Linh từng đến tử phong chờ nhiều ngày. Ngân Nguyệt được giao quản lý mọi việc.","theLucLienQuan":[],"nguon":["@c0640"]},{"id":"tu-phong-dong-phu","name":"Tử Phong động phủ","cn":"","capDo":"khac","parentId":"chu-phong-lac-van-tong","blurb":"Động phủ nơi Mộ Phái Linh bế quan khổ tu, nằm trong khu vực Lạc Vân Tông.","detail":"Hàn Lập ghé Tử Phong động phủ dùng thần thức kiểm tra Mộ Phái Linh đang bế quan, thấy tu vi tiến bộ nên âm thầm rời đi không quấy nhiễu.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0644"]},{"id":"ngu-quoc","name":"Ngu quốc","cn":"虞国","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Quốc gia trung lập trong Cửu quốc liên minh, nơi tổ chức hội giao dịch lớn nhất Thiên Nam.","detail":"Ngu quốc là quốc gia trung lập trong cửu quốc liên minh, đối diện uy hiếp thường trực của pháp sĩ Mộ Lan nên ít gây nghi kỵ cho các thế lực khác. Hai năm sau sẽ tổ chức hội giao dịch lớn nhất Thiên Nam, quy tụ kỳ trân dị bảo cùng gần phân nửa tu sĩ Nguyên Anh Kỳ.","theLucLienQuan":["Cửu quốc liên minh"],"nguon":["@c0644","@c0668","@c0718","@c0745"]},{"id":"dai-tan-de-quoc","name":"Đại Tấn đế quốc","cn":"大晋帝国","capDo":"quoc-gia","parentId":null,"blurb":"Đế quốc xa xôi mà Hàn Lập nghĩ tới như phương án dự phòng nếu không tìm được Canh Tinh ở Thiên Nam.","detail":"Hàn Lập nhắc tới Đại Tấn đế quốc như khả năng phải đi nếu không tìm được Canh Tinh tại hội giao dịch Ngu quốc.","theLucLienQuan":[],"nguon":["@c0644"]},{"id":"tu-dao-son","name":"Tử Đạo Sơn","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Thâm sơn ở phía tây Nguyên Vũ quốc, tọa địa của Phó gia, bị tử sắc vụ khí độc bao phủ nhiều năm, có trận Độc Vân Tử Chướng Trận bảo vệ.","detail":"Nằm ở phía tây Nguyên Vũ quốc, thâm sơn này bị tử vụ độc bao phủ nhiều năm khiến phàm nhân đi vào không thấy đường, ở lâu thì mắt chảy lệ, yết hầu chảy máu, thậm chí bỏ mạng. Phó gia mời đại sư bố trí trận Độc Vân Tử Chướng Trận, người lạc vào chết trong trận được coi như vật tế lễ.","theLucLienQuan":["Phó gia"],"nguon":["@c0645"]},{"id":"thai-hoa-tran","name":"Thái Hòa","cn":"","capDo":"thanh","parentId":"nguyen-vu-quoc","blurb":"Trấn nhỏ cách Tử Đạo Sơn khoảng mười dặm, dân cư chừng mười vạn, có hai khách điếm. Nơi Hàn Lập cùng hai tu sĩ đồng hành trọ chờ dịp thọ đản Phó gia.","detail":"Trấn Thái Hòa nằm cách Tử Đạo Sơn khoảng mười dặm, dân cư chừng mười vạn nhưng tửu lâu khách điếm đầy đủ. Hàn Lập cùng La huynh và đại hán đến đây trọ tại khách điếm Vĩnh Khúc chờ ngày thọ đản lão tổ Phó gia.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"vinh-khuc-khach-diem","name":"Vĩnh Khúc","cn":"","capDo":"khac","parentId":"thai-hoa-tran","blurb":"Một trong hai khách điếm ở trấn Thái Hòa, nơi A Nhị làm tiểu nhị và ba tu sĩ đồng hành trọ lại.","detail":"Khách điếm Vĩnh Khúc tại trấn Thái Hòa, do Lưu chưởng quỹ quản lý, nơi Hàn Lập cùng La huynh và đại hán thuê phòng hảo hạng chờ thọ đản Phó gia.","theLucLienQuan":[],"nguon":["@c0645"]},{"id":"khach-diem-nguyen-vu","name":"Khách điếm trong thành","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Khách điếm nơi Hàn Lập và Bành Dịch Song Hung ở lại hơn mười ngày, cũng là nơi Hàn Lập nghe lén toàn bộ âm mưu đoạt bảo qua vách.","detail":"Khách điếm trong thành thuộc Nguyên Vũ Quốc, nơi Hàn Lập lưu trú và bình tĩnh thổ nạp luyện khí trong phòng bên cạnh hai hung tu. Bành Dịch Song Hung tưởng đã dùng lồng cách âm nhưng không che nổi thần thức của Hàn Lập.","theLucLienQuan":[],"nguon":["@c0646"]},{"id":"tieu-son-phuc-kich","name":"Tiểu sơn u tĩnh","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Tiểu sơn vắng người cách hơn trăm dặm, nơi Bành Dịch Song Hung dẫn Hàn Lập tới để phục kích.","detail":"Ngọn núi nhỏ u tĩnh không người, cách nơi Hàn Lập ở hơn trăm dặm. Phía sau có tiểu cốc bí ẩn được hai hung tu bố trí cấm chế và trận pháp vây địch đơn giản làm bẫy. Hàn Lập phát hiện toàn bộ bằng thần thức và chủ động vạch mặt ý đồ tại đây.","theLucLienQuan":["Bành Dịch Song Hung"],"nguon":["@c0646"]},{"id":"ky-linh-son","name":"Kỳ Linh Sơn","cn":"","capDo":"khac","parentId":"thien-la-quoc","blurb":"Dãy núi phía tây Thiên La Quốc, kéo dài mấy vạn dặm, nhiều linh thú kỳ trùng, là nơi đặt căn cứ của Ngự Linh Tông.","detail":"Kỳ Linh Sơn nằm phía tây Thiên La Quốc, dài liên tiếp mấy vạn dặm, có nhiều linh thú kỳ trùng. Lão già Ngự Linh Tông ngồi trong phòng đá đen nhánh tại đây khi phát hiện Mộc Linh Anh bị giam cầm.","theLucLienQuan":["Ngự Linh Tông"],"nguon":["@c0648"]},{"id":"thien-la-quoc","name":"Thiên La Quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia nơi có Kỳ Linh Sơn và địa bàn liên quan đến Ngự Linh Tông cùng Ma đạo Lục tông.","detail":"Thiên La Quốc có Kỳ Linh Sơn phía tây là căn cứ Ngự Linh Tông. Được nhắc đến trong bối cảnh Ma đạo Lục tông có địa bàn tại đây.","theLucLienQuan":["Ngự Linh Tông","Ma đạo Lục tông"],"nguon":["@c0648"]},{"id":"pho-gia-bao","name":"Phó Gia Bảo","cn":"","aliases":["Cự bảo Phó gia"],"capDo":"thanh","parentId":"tu-dao-son","blurb":"Căn cứ cự bảo của Phó gia trong Tử đạo sơn, nơi tất bật chuẩn bị thọ yến bốn trăm tuổi cho Phó Thiên Hóa.","detail":"Cự bảo của gia tộc Phó gia nằm trong Tử đạo sơn, nơi các vãn bối bận rộn chuẩn bị thọ đản cho đương kim gia chủ Phó Thiên Hóa.","theLucLienQuan":["Phó gia"],"nguon":["@c0648"]},{"id":"tieu-son-an-cu-tan-nhu-am","name":"Tiểu sơn vô danh (nơi ẩn cư cũ Tân Như Âm)","cn":"","capDo":"khac","parentId":"nguyen-vu-quoc","blurb":"Ngọn núi nhỏ vô danh tại Nguyên Vũ Quốc, sườn núi có sương mù cấm chế bao phủ. Bên trong có trúc lâu cổ xưa — nơi ở cũ của Tân Như Âm, hiện do hậu nhân Tiểu Mai trú ngụ. Tầng hai lầu các có bàn gỗ hoàng mộc đặt hai bài vị Tề Vân Tiêu và Tân Như Âm.","detail":"Hàn Lập bay tới đây sau khi diệt Phó Gia bảo, phá cấm chế dễ dàng để bái tế Tân Như Âm và Tề Vân Tiêu. Gặp hậu nhân Tiểu Mai đang ở tạm tại trúc lâu.","theLucLienQuan":[],"nguon":["@c0652"]},{"id":"con-moc-son","name":"Côn Mộc sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Trữ sư thúc cùng đệ tử dẫn Mộc Linh Anh đi qua, xảy ra sự cố Linh Anh chạy thoát.","detail":"Địa điểm trên đường Ngự Linh Tông hộ tống Mộc Linh Anh, nơi xảy ra sự cố Linh Anh chạy thoát.","theLucLienQuan":["Ngự Linh Tông"],"nguon":["@c0655"]},{"id":"tong-dan-quy-linh-mon","name":"Tổng đàn Quỷ Linh Môn","cn":"","capDo":"khac","parentId":"viet-quoc","blurb":"Tổng đàn hiện tại của Quỷ Linh Môn, đặt tại vị trí tông môn Yểm Nguyệt Tông năm xưa.","detail":"Quỷ Linh Môn chiếm lĩnh toàn Việt Quốc, đặt tổng đàn tại chỗ tông môn Yểm Nguyệt Tông cũ.","theLucLienQuan":["Quỷ Linh Môn","Yểm Nguyệt Tông"],"nguon":["@c0655"]},{"id":"nhac-phan-dan","name":"Nhạc phân đàn","cn":"","capDo":"khac","parentId":null,"blurb":"Một phân đàn của Toái Hồn Môn thuộc Quỷ Linh Môn.","detail":"Được nhắc khi Tam sư huynh bảo Ngũ sư muội dùng Truyền âm phù liên lạc Nhạc phân đàn trong quá trình truy tìm hung thủ giết Lục sư đệ.","theLucLienQuan":["Toái Hồn Môn","Quỷ Linh Môn"],"nguon":["@c0656"]},{"id":"thanh-nguu-tran","name":"Thanh Ngưu Trấn","cn":"青牛镇","capDo":"thanh","parentId":"kinh-chau","blurb":"Trấn nhỏ nơi Hàn Lập sống thời niên thiếu, sau hơn trăm năm đã biến thành thành trấn phồn hoa rộng vài dặm vuông.","detail":"Hàn Lập bay trên không nhận ra trấn cũ nhờ ngã tư đường quen thuộc. Thi triển ẩn nặc pháp thuật hạ xuống đi bộ vào trấn, kinh ngạc trước sự đổi thay.","theLucLienQuan":["Thất Huyền Môn"],"nguon":["@c0657"]},{"id":"tuu-lau-huong-xuan","name":"Tửu lâu Hương Xuân","cn":"","capDo":"khac","parentId":"thanh-nguu-tran","blurb":"Tòa tiểu lâu cũ nát một trệt một lầu ở ngã ba trong Thanh Ngưu Trấn, nơi Hàn Lập từng sống hai năm cùng Tam thúc.","detail":"Bảng hiệu Hương Xuân còn sót lại. Hàn Lập dừng lại trước đây hoài niệm về Tam thúc và kỷ niệm xưa, nhớ lại gương mặt béo tròn của Tam thúc ngồi ghế nhả khói thuốc ăn trái cây.","theLucLienQuan":[],"nguon":["@c0657"]},{"id":"thanh-son","name":"Thanh Sơn","cn":"青山","capDo":"khac","parentId":"kinh-chau","blurb":"Nơi Hàn Lập đứng trên không trung nhìn xuống quê cũ Ngũ Lý Câu, chứng kiến cảnh thay đổi hoàn toàn.","detail":"Ngọn núi gần Ngũ Lý Câu tại Kính Châu, Hàn Lập bay tới không trung Thanh Sơn quan sát quê cũ đã thay đổi từ nhà cỏ thành đại viện lợp ngói.","theLucLienQuan":["Hàn gia Kính Châu"],"nguon":["@c0658"]},{"id":"han-gia-tu","name":"Hàn Gia Từ","cn":"韩家祠","capDo":"khac","parentId":"ngu-ly-cau","blurb":"Từ đường Hàn gia, lầu các ở giữa khu vực quê cũ Ngũ Lý Câu, tấm biển ngân phấn.","detail":"Tầng trệt có mấy trăm bài vị gỗ xếp trên bàn thờ bốn phía, toàn tên họ Hàn. Tầng lầu thờ linh vị trang trọng hơn với lô hương, đàn hương, đỉnh đồng lớn, có linh vị Hàn Chú, Hàn Thiết, Hàn Thiên Sinh. Nơi thờ phụng bản chép tay gia tổ, phía sau ghi một bộ pháp vô danh.","theLucLienQuan":["Hàn gia Kính Châu"],"nguon":["@c0658"]},{"id":"tu-duong-han-gia","name":"Từ đường Hàn gia","cn":"","capDo":"khac","parentId":null,"blurb":"Từ đường gia tộc Hàn gia, nơi đặt linh vị tổ tiên, bàn thờ chứa hộp gỗ bản chép tay bí mật và vật cũ tổ tiên trên mâm phủ vải đỏ.","detail":"Từ đường gia tộc Hàn gia, nơi diễn ra cuộc gặp gỡ giữa Hàn Lập và hậu nhân Hàn Thiên Khiếu cùng Lệ đại hán. Bên trong có bàn thờ đặt linh vị tổ tiên, hộp gỗ chứa bản chép tay bí mật gia tộc chỉ lịch đại gia chủ mới biết, và các vật dụng cũ của tổ tiên (cung tên nhỏ, cài tóc gỗ) đặt trên mâm phủ vải đỏ.","theLucLienQuan":["Hàn gia"],"nguon":["@c0659"]},{"id":"tong-duong-han-gia","name":"Tông đường Hàn gia","cn":"","capDo":"khac","parentId":"han-gia-tu","blurb":"Tông đường chính của Hàn gia, nơi Hàn Lập gặp hậu nhân và đặt Phệ Linh Kiếm trấn gia. Trong vách tường có khoang bí mật chứa bức họa lụa của tiền nhân.","detail":"Nơi Hàn Lập gặp Vân Thiên Khiếu và Lệ Phong, đặt Phệ Linh Kiếm lên bàn thờ chỗ trang trọng nhất. Trong vách tường có khoang bí mật chứa năm sáu bức họa lụa: bức vẽ Hàn Lập thời trẻ 17-18 tuổi, bức họa phụ thân mặc trang phục viên ngoại, và các bức họa huynh trưởng lúc già. Phệ Linh Kiếm không thể di chuyển ra khỏi tông đường, rút kiếm thì trong tông đường an toàn, ngoài 10 dặm mọi sinh vật bị tiêu diệt.","theLucLienQuan":["Hàn gia"],"nguon":["@c0660"]},{"id":"phan-dan-lam-chau-quy-linh-mon","name":"Phân đàn Quỷ Linh Môn Lam Châu","cn":"","capDo":"khac","parentId":"lam-chau","blurb":"Phân đàn của Quỷ Linh Môn đặt tại vùng phụ cận Lam Châu, nơi nhóm Ngự Linh Tông định chạy tới mượn trận pháp tự bảo vệ.","detail":"Phân đàn của Quỷ Linh Môn tại phụ cận Lam Châu. Nữ tử họ Liễu ra lệnh nhóm chạy về đây mượn trận pháp tự bảo vệ khi bị Hàn Lập truy đuổi.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0661"]},{"id":"tong-dan-lien-minh-chin-nuoc","name":"Tổng đàn liên minh chín nước","cn":"","capDo":"thanh","parentId":"thien-nam","blurb":"Tòa thành tu sĩ duy nhất tại Thiên Nam, tọa lạc phía bắc Thiên Nam đế quốc. Là tổng đàn liên minh chín nước, nơi tổ chức Giao dịch hội.","detail":"Tọa lạc phía bắc Thiên Nam đế quốc, là tòa thâm sơn do thiên nhiên tạo thành, cũng là tòa thành tu sĩ duy nhất tại Thiên Nam. Ngoài Cửu Quốc Minh lão quái còn có sáu bảy tu sĩ Nguyên Anh Trung Kỳ trấn giữ. Liên minh chín nước tổ chức Giao dịch hội tại đây, mở địa trận Thượng Nguyên Diệt Quang trận bảo vệ khu vực.","theLucLienQuan":["Liên minh chín nước"],"nguon":["@c0670"]},{"id":"thien-nam-de-quoc","name":"Thiên Nam đế quốc","cn":"","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Quốc gia nằm tại Thiên Nam, phía bắc có tổng đàn liên minh chín nước.","detail":"Quốc gia thuộc vùng Thiên Nam, phía bắc là nơi tọa lạc tổng đàn liên minh chín nước — tòa thành tu sĩ duy nhất Thiên Nam, nơi tổ chức Giao dịch hội.","theLucLienQuan":[],"nguon":["@c0670"]},{"id":"thien-la-de-quoc","name":"Thiên La Đế Quốc","cn":"天罗帝国","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Đế quốc thuộc Chính đạo, trước kia là nơi Chính đạo tổ chức Giao dịch hội.","detail":"Thiên La Đế Quốc là nơi Chính đạo trước kia tổ chức Giao dịch hội, trước khi quyền tổ chức rơi vào tay Cửu Quốc Minh.","theLucLienQuan":["Chính đạo"],"nguon":["@c0671"]},{"id":"phong-do-de-quoc","name":"Phong Đô Đế Quốc","cn":"风都帝国","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Đế quốc thuộc Tà đạo, trước kia là nơi Tà đạo tổ chức Giao dịch hội.","detail":"Phong Đô Đế Quốc là nơi Tà đạo trước kia tổ chức Giao dịch hội, trước khi quyền tổ chức rơi vào tay Cửu Quốc Minh.","theLucLienQuan":["Tà đạo"],"nguon":["@c0671"]},{"id":"dien-thien-thanh","name":"Điền Thiên Thành","cn":"田天城","aliases":["Thiên Thành","Thiên Quốc thành","Thành Điền Thiên"],"capDo":"thanh","parentId":"thien-nam","blurb":"Thạch thành cự đại do Cửu Quốc Minh trước sau mấy lần xây dựng bổ sung, toàn bộ dùng cự thạch, dài hơn trăm dặm, xếp vào top năm thành lớn nhất Thiên Nam.","detail":"Toàn bộ thạch thành dùng cự thạch xây thành, dài hơn trăm dặm, xếp vào top năm thành lớn nhất Thiên Nam nhưng Hàn Lập cho rằng không bằng Thiên Tinh Thành ở Loạn Tinh Hải. Khu vực phụ cận có cấm chế cấm phi hành, tu sĩ phải đi bộ vào thành. Cửa thành cao hơn mười trượng, có tu sĩ chấp pháp Cửu Quốc Minh canh gác. Bên trong thạch ốc chỉnh tề, phố rộng giao nhau như mạng nhện. Có khu lầu các riêng dành cho tu sĩ Nguyên Anh, bao quanh bởi bạch sắc quang mạc cấm chế.","theLucLienQuan":["Cửu Quốc Minh"],"nguon":["@c0674","@c0685","@c0746"]},{"id":"tinh-long-cac","name":"Tinh Long Các","cn":"","capDo":"khac","parentId":"dien-thien-thanh","blurb":"Lầu các ba tầng trắng noãn như ngọc trong Điền Thiên Thành, nơi Thiên Tinh Chân Nhân tổ chức Giao hoán hội dành tu sĩ Nguyên Anh.","detail":"Lầu các ba tầng, diện tích từ lớn đến nhỏ, bề ngoài trắng noãn như ngọc. Nằm trong Điền Thiên Thành, là nơi tổ chức Giao hoán hội do Thiên Tinh Chân Nhân chủ trì, tham gia phải mang mặt nạ che chân diện mục.","theLucLienQuan":["Cửu Quốc Minh"],"nguon":["@c0674"]},{"id":"lau-cac-giao-hoan-hoi","name":"Lầu các Giao hoán hội","cn":"","capDo":"khac","parentId":"dien-thien-thanh","blurb":"Lầu các bí mật do Thiên Tinh Chân Nhân tổ chức Giao hoán hội Nguyên Anh kỳ. Bên ngoài phủ huyễn thuật trông như tửu lâu bình thường.","detail":"Bên ngoài là huyễn thuật cảnh tửu lâu đông khách, có biển gỗ ghi được bao. Bước vào thì cảnh tượng tan biến, tầng một trống rỗng chỉ có bàn gỗ cổ và đèn Thanh Đồng. Tầng hai diện tích lớn hơn bề ngoài nhiều lần, trên nóc và vách tường khảm hơn trăm khối nguyệt quang thạch chiếu sáng, sát vách bốn phía có bàn ghế cho tu sĩ Nguyên Anh ngồi.","theLucLienQuan":[],"nguon":["@c0675"]},{"id":"truy-ma-coc","name":"Trụy Ma Cốc","cn":"坠魔谷","capDo":"khac","parentId":"thien-nam","blurb":"Đệ nhất hung địa Thiên Nam, chiến trường thượng cổ nơi ma tu đại thần thông chém giết nhau bằng cấm chế kỳ trận thời hoang dã.","detail":"Chiến trường thượng cổ nơi các ma tu đại thần thông dùng cấm chế kỳ trận chém giết nhau thời kỳ hoang dã, thần thông quá kinh người xé rách khe không gian. Tất cả đám tu sĩ thượng cổ đều chết, sát khí do cổ trận tụ lại không tán, không gian sơn cốc không ổn định. Suốt nhiều năm, không dưới một ngàn tu sĩ cao cấp vào tầm bảo đều tử vong, pháp bảo tùy thân cũng lạc lại bên trong. Gần vạn năm qua không còn ai dám vào, trở thành nơi đệ nhất hung ác Thiên Nam. Toàn bộ tu sĩ Thiên Nam đều biết bảo vật bên trong đông đảo nhưng không dám mạo hiểm.","theLucLienQuan":[],"nguon":["@c0677"]},{"id":"phuong-thi-phia-tay-thanh-dien-thien","name":"Phường thị phía tây Thành Điền Thiên","cn":null,"capDo":"khac","parentId":"dien-thien-thanh","blurb":"Khu phường thị rộng lớn nằm phía tây Thành Điền Thiên, lớn hơn phường thị ba phái tại Vân Mộng Sơn rất nhiều.","detail":"Nơi Hàn Lập đến mua sắm tài liệu chế phù gồm nguyên liệu phụ trợ giấy phù và mực cao cấp, chuẩn bị luyện chế Hàng Linh Phù. Phường thị có bán bút chế phù nhưng chỉ đỉnh cấp thông thường, không đủ cấp để chế mật phù. Quy mô lớn hơn rất nhiều so với phường thị ba phái tại Vân Mộng Sơn.","theLucLienQuan":[],"nguon":["@c0678"]},{"id":"dong-phu-thuong-khon-thuong-nhan","name":"Động phủ Thương Khôn Thượng Nhân","cn":"","capDo":"khac","parentId":"mo-lan-thao-nguyen","blurb":"Động phủ bí mật của Thương Khôn Thượng Nhân nằm ở vòng ngoài Mộ Lan thảo nguyên, khoảng một trăm dặm, nơi hắn toạ hoá sau khi ra khỏi Truỵ Ma Cốc.","detail":"Nơi lưu giữ bảo vật lấy từ Truỵ Ma Cốc cùng công pháp và pháp bảo bản thân Thương Khôn Thượng Nhân. Bên ngoài được bảo vệ bởi Thái Diệu Thần Cấm — một trong thập đại thượng cổ cấm chế đã thất truyền, cần tám tu sĩ thần thức cường đại dùng thần thức biến hoá thần thông để phá giải.","theLucLienQuan":[],"nguon":["@c0684"]},{"id":"vung-hoang-da-cuu-quoc-mo-lan","name":"Vùng hoang dã giữa Cửu Quốc Minh và Mộ Lan thảo nguyên","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng hoang dã kéo dài hàng ngàn dặm giữa Cửu Quốc Minh và Mộ Lan thảo nguyên, cây cỏ ít, cuồng phong bụi vàng, là chiến trường thường xuyên của tu sĩ hai bên.","detail":"Nơi tu sĩ và pháp sĩ hai bên thường đánh nhau sống chết, số người chết lên tới hàng vạn. Chủ yếu tu sĩ Trúc Cơ Kỳ, đôi khi có Kết Đan Kỳ. Đoàn chín Nguyên Anh bay ngang qua vùng này trên đường tới Mộ Lan thảo nguyên.","theLucLienQuan":["Cửu Quốc Minh","Mộ Lan thảo nguyên"],"nguon":["@c0685"]},{"id":"hoang-sa-phong-tran","name":"Hoàng Sa Phong Trận","cn":"","capDo":"khac","parentId":"mo-lan-thao-nguyen","blurb":"Đại phong trận bão cát tứ phía trong vùng hoang dã, thần thức không xuyên qua được, bên trong có bóng đen bí ẩn chứa kẻ ẩn thân giám sát.","detail":"Trận pháp bão cát khổng lồ nơi nhóm Nam Lũng Hầu vừa rời khỏi. Thần thức không xuyên qua bão cát, chỉ dùng linh mục thần thông mới phát hiện vòng tròn bóng đen chứa mấy người có pháp lực vượt Nguyên Anh ẩn thân giám sát bên trong.","theLucLienQuan":[],"nguon":["@c0688"]},{"id":"thach-son-dong-phu-thuong-nhan","name":"Thạch sơn (động phủ thượng nhân)","cn":"","capDo":"khac","parentId":"mo-lan-thao-nguyen","blurb":"Núi đá trụi lủi cao hơn trăm trượng, không một ngọn cỏ, linh khí thiếu thốn, nằm ở bờ phía tây Mộ Lan thảo nguyên. Ẩn chứa động phủ của thượng nhân, được bảo vệ bởi cấm chế ngoại tầng.","detail":"Thạch sơn trụi lủi cao hơn trăm trượng, không cỏ, linh khí thiếu thốn, nằm ở bờ tây thảo nguyên. Bên trong ẩn giấu động phủ của thượng nhân (Thương Khôn Thượng Nhân). Nam Lũng Hầu và Bạch sam lão giả dùng hai lá tiểu kỳ khai mở cấm chế ngoại tầng, mặt đất rung động dữ dội.","theLucLienQuan":[],"nguon":["@c0693"]},{"id":"tieu-thach-son-bao-kho","name":"Tiểu thạch sơn (núi đá chứa bảo khố)","cn":"","capDo":"khac","parentId":"thach-son-dong-phu-thuong-nhan","blurb":"Ngọn núi đá nhỏ bị Nam Lũng Hầu và bạch sam lão giả bửa đôi bằng chú ngữ, bên trong có bậc thang đá dẫn xuống sâu hơn trăm trượng tới đại sảnh lam quang. Khe núi tự khép lại do cấm chế bên ngoài khởi động.","detail":"Nằm trong khu vực động phủ Thương Khôn Thượng Nhân. Bị bửa đôi bằng thần thông, hé ra khe rộng hơn mười trượng. Bên trong có thông đạo cầu thang đá hai vách khảm nguyệt quang thạch, ánh sáng chuyển từ trắng sang u lục khi xuống sâu. Cấm chế bên ngoài tự khởi động theo chu kỳ khép khe núi lại, cần đợi ba ngày đến lúc yếu nhất mới tách được lần nữa.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"dai-sanh-lam-quang","name":"Đại sảnh lam quang (dưới lòng núi)","cn":"","capDo":"khac","parentId":"tieu-thach-son-bao-kho","blurb":"Gian đại sảnh dưới lòng núi đá, bốn vách tường lam quang trong suốt như phỉ thúy, được Thái Diệu Thần Cấm bảo vệ.","detail":"Nằm sâu hơn trăm trượng dưới tiểu thạch sơn. Rộng hơn mười trượng, bốn vách tường lam quang trong suốt phảng phất như phỉ thúy cự đại kéo giãn ra. Thần thức chạm vào vách tường bị bắn ngược. Lối vào biến mất sau khi cấm chế bên ngoài khởi động, biến đại sảnh thành không gian kín bưng.","theLucLienQuan":[],"nguon":["@c0694"]},{"id":"ngoc-ki-cac","name":"Ngọc Ki Các","cn":"玉機閣","capDo":"khac","parentId":"dong-phu-thuong-khon-thuong-nhan","blurb":"Lầu các hai tầng bằng bạch ngọc trong suốt cao hơn mười trượng, nằm bên trong thạch môn sau khi phá cấm chế tinh tường trong động phủ Thương Khôn Thượng Nhân.","detail":"Lầu các hai tầng bằng bạch ngọc trong suốt, cao hơn mười trượng, trên cao khắc ba chữ Ngọc Ki Các màu bạc. Phía trước có bàn thờ đen cổ kính thờ quyển trục ngân bạch. Tầng một chứa ba giá gỗ lớn bày đầy bảo vật tỏa hào quang chói mắt. Tầng hai chưa được khám phá.","theLucLienQuan":["Thương Khôn Thượng Nhân"],"nguon":["@c0696"]},{"id":"thach-mon-dong-phu-thuong-nhan","name":"Thạch môn (động phủ Thương Khôn Thượng Nhân)","cn":"","capDo":"khac","parentId":"dong-phu-thuong-khon-thuong-nhan","blurb":"Cánh cửa đá cao bảy tám trượng, rộng ba bốn trượng, lộ ra sau khi tinh tường bị phá, dẫn vào không gian chứa Ngọc Ki Các.","detail":"Thạch môn nằm trên thạch bích, lộ ra sau khi Hàn Lập phá hủy cấm chế tinh tường. Cao bảy tám trượng, rộng ba bốn trượng, dẫn vào không gian rộng lớn bên trong chứa lầu các Ngọc Ki Các.","theLucLienQuan":[],"nguon":["@c0696"]},{"id":"hu-thien-dien-tang-mot","name":"Hư Thiên điện — Tầng một","capDo":"khac","parentId":"dong-phu-thuong-khon-thuong-nhan","blurb":"Tầng một Hư Thiên điện, nơi chứa ba giá gỗ bảo vật gồm Cổ Bảo, pháp bảo, tài liệu và đan dược. Có bồ đoàn và chậu Âm Ngưng thảo ở cửa sổ.","detail":"Tầng một của Hư Thiên điện trong động phủ Thương Khôn Thượng Nhân. Ba giá gỗ xếp thành ba hàng: giá thứ nhất chứa 16 kiện gồm Cổ Bảo và pháp bảo; giá thứ hai chứa tài liệu hi hữu (khối sắt, bảo thạch huyết hồng); giá thứ ba chứa vài bình đan dược. Cửa sổ có bồ đoàn và chậu Âm Ngưng thảo xanh biếc.","theLucLienQuan":[],"nguon":["@c0697"]},{"id":"hu-thien-dien-tang-hai","name":"Hư Thiên điện — Tầng hai","capDo":"khac","parentId":"dong-phu-thuong-khon-thuong-nhan","blurb":"Tầng hai Hư Thiên điện, phòng ngủ Thương Khôn Thượng Nhân. Có điện thờ yêu thần ba đầu sáu tay, giường hàn ngọc xanh với ba hộp ngọc đầu giường.","detail":"Phòng ngủ Thương Khôn Thượng Nhân tại tầng hai Hư Thiên điện. Mùi đàn hương nồng. Góc tường có điện thờ với tượng vàng yêu thần một sừng ba đầu sáu tay, trước điện có hỏa hồng tiểu lô đỉnh phát khí trắng. Bên trái điện thờ có ghế gỗ với nghiên mực, bút lông, trúc giản. Đối diện có giường hàn ngọc xanh phát âm hàn khí, đầu giường có ba hộp ngọc lớn nhỏ không đồng nhất.","theLucLienQuan":[],"nguon":["@c0697"]},{"id":"phong-nguyen-quoc","name":"Phong Nguyên Quốc","cn":"丰原国","capDo":"quoc-gia","parentId":"cuu-quoc-minh","blurb":"Một trong ba quốc gia thuộc Cửu Quốc Minh gần Mộ Lan thảo nguyên nhất. Bình thường có đông đảo tu sĩ trấn thủ trên linh sơn biên giới, nhưng sau khi bị Mộ Lan đánh lén thì tu sĩ đã lui về phía sau.","detail":"Hàn Lập tiến vào Phong Nguyên Quốc trên đường từ Mộ Lan thảo nguyên xuyên hoang nguyên về Thiên Nam. Đi mấy ngày không thấy tu sĩ Cửu Quốc, chỉ có khí tức pháp sĩ Mộ Lan tuần tra, cho thấy chiến sự bất lợi.","theLucLienQuan":["Cửu Quốc Minh","Người Mộ Lan"],"nguon":["@c0704"]},{"id":"linh-lung-son","name":"Linh Lung Sơn","cn":"","capDo":"khac","parentId":"bac-luong-quoc","blurb":"Tân sơn môn Yểm Nguyệt Tông, nằm phía Tây Bắc Lương Quốc.","detail":"Linh Lung Sơn là tân sơn môn của Yểm Nguyệt Tông, nằm phía Tây Bắc Lương Quốc. Chia ba tầng theo tu vi: chân núi dành cho đệ tử cấp thấp Luyện Khí kỳ, từ chân tới lưng chừng dành cho Trúc Cơ kỳ, trên cùng dành cho Kết Đan kỳ.","theLucLienQuan":["Yểm Nguyệt Tông"],"nguon":["@c0708"]},{"id":"bac-luong-quoc","name":"Bắc Lương Quốc","cn":"","capDo":"quoc-gia","parentId":"cuu-quoc-minh","blurb":"Nơi lục phái Việt Quốc trú chân sau khi gia nhập Cửu Quốc Minh, tài nguyên tu luyện đội sổ.","detail":"Bắc Lương Quốc là quốc gia thuộc Cửu Quốc Minh, nơi lục phái Việt Quốc trú chân sau khi bại lui. Tài nguyên tu luyện đội sổ trong Cửu Quốc Minh, lục phái mất trăm năm mới bén rễ. Yểm Nguyệt Tông đặt tân sơn môn Linh Lung Sơn ở phía Tây, Viên gia ở phía Bắc.","theLucLienQuan":["Yểm Nguyệt Tông","Viên gia"],"nguon":["@c0708"]},{"id":"tieu-thanh-chan-linh-lung-son","name":"Tiểu thành dưới chân Linh Lung sơn","cn":"","capDo":"thanh","parentId":"bac-luong-quoc","blurb":"Tiểu thành nằm dưới chân Linh Lung sơn, nơi Hàn Lập nghỉ ngơi một ngày và dò tìm tu sĩ Yểm Nguyệt Tông cấp thấp.","detail":"Tiểu thành dưới chân Linh Lung sơn, Viên Khôn thường tới đây mua sắm vật phẩm thế tục cho thương điếm của tông. Hàn Lập dừng lại nghỉ ngơi một ngày, dùng thần thức dò xét tu sĩ trong thành và đánh dấu Viên Khôn làm mục tiêu.","theLucLienQuan":["Yểm Nguyệt Tông"],"nguon":["@c0709"]},{"id":"thuong-tang-linh-lung-son","name":"Thượng tầng Linh Lung sơn","cn":"","capDo":"khac","parentId":"linh-lung-son","blurb":"Khu vực thượng tầng của Linh Lung sơn, có cấm chế rất lợi hại, nguy hiểm hơn trung tầng nhiều. Tu sĩ cấp cao cư trú, có cổng canh Trúc Cơ kỳ và tu sĩ Kết Đan tuần tra.","detail":"Thượng tầng núi có hệ thống cấm chế lợi hại, lọt vào không có đường sống. Cổng canh do hai tu sĩ Trúc Cơ kỳ trấn giữ, có tu sĩ Kết Đan sơ kỳ Lam sư bá tuần tra. Số lượng tu sĩ cấp cao ở đây rất ít.","theLucLienQuan":["Linh Lung sơn"],"nguon":["@c0710"]},{"id":"dong-phu-nam-cung-uyen","name":"Động phủ Nam Cung Uyển","cn":"","capDo":"khac","parentId":"thuong-tang-linh-lung-son","blurb":"Động phủ của Nam Cung Uyển nằm gần đỉnh núi cao nhất Linh Lung sơn. Bên trong bố trí tao nhã tinh xảo, thoang thoảng mùi hương gỗ.","detail":"Động phủ nằm ở gần đỉnh núi cao nhất, bên trong có hành lang ngắn dẫn tới mấy gian phòng nhỏ và đại sảnh. Đại sảnh bố trí tao nhã tinh xảo, thoang thoảng mùi hương gỗ, có hai giá hoa cổ kính đặt kỳ thảo trân quý xanh biếc, bàn nhỏ hình vuông với hai ghế nhỏ xanh nhạt.","theLucLienQuan":["Linh Lung sơn"],"nguon":["@c0710"]},{"id":"huyet-sac-thi-luyen","name":"Huyết Sắc Thí Luyện","cn":"","capDo":"khac","parentId":null,"blurb":"Cấm địa nơi Nam Cung Uyển và Hàn Lập thất thân, sự kiện trở thành nguồn gốc tâm ma của Nam Cung Uyển.","detail":"Được nhắc trong hồi ức của Nam Cung Uyển khi kể lại tâm lộ trình với Hàn Lập.","theLucLienQuan":[],"nguon":["@c0711"]},{"id":"dai-sanh-dong-phu-nam-cung-uyen","name":"Đại sảnh động phủ Nam Cung Uyển","cn":"","capDo":"khac","parentId":null,"blurb":"Đại sảnh (thính đường) trong động phủ của Nam Cung Uyển tại Yểm Nguyệt Tông, nơi diễn ra toàn bộ chuẩn bị phục kích sư tỷ Nguyên Anh trung kỳ.","detail":"Nơi Hàn Lập bố trí trận kỳ trận bàn khắp sảnh, Phệ Kim Trùng ẩn nóc, Ngân Nguyệt ẩn dưới đất và trong vách. Có cột đá chứa cấm chế quang mạc xanh để bảo vệ người bên trong.","theLucLienQuan":["Yểm Nguyệt Tông"],"nguon":["@c0713"]},{"id":"lac-van-dien","name":"Lạc Vân Điện","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi sư tỷ của Nam Cung Uyển cư ngụ, cấm chế rất mạnh.","detail":"Được Nam Cung Uyển nhắc đến khi giải thích vì sao không nên chủ động đến đó tấn công sư tỷ, do cấm chế nơi này rất mạnh.","theLucLienQuan":["Yểm Nguyệt Tông"],"nguon":["@c0713"]},{"id":"lac-nhat-dien","name":"Lạc Nhật Điện","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi cư ngụ truyền đời của đại trưởng lão Yểm Nguyệt Tông, xây gần linh nhãn, cấm chế rất mạnh, ngoài mấy vị trưởng lão không ai được phép đến gần.","detail":"Lạc Nhật Điện nằm gần linh nhãn thuộc Yểm Nguyệt Tông, có cấm chế bảo vệ nghiêm ngặt. Đại trưởng lão cư ngụ tại đây, nhận Truyền Âm phù rồi hóa bạch hồng bay tới động phủ Nam Cung Uyển.","theLucLienQuan":["Yểm Nguyệt Tông"],"nguon":["@c0714"]},{"id":"cuu-quoc-minh","name":"Cửu Quốc Minh","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Khu vực tiền tuyến nơi liên minh tu sĩ Thiên Nam hội nghị và phối hợp chống Mộ Lan. Bối Diệp Tông và Hóa Ý Môn chủ sự tại đây.","detail":"Nơi diễn ra hội nghị Nguyên Anh tu sĩ Thiên Nam bàn chiến cục chống Mộ Lan. Bối Diệp Tông (tông chủ Ngô Bằng) và Hóa Ý Môn (Thích phu nhân) là hai đại phái hàng đầu chủ sự.","theLucLienQuan":["Bối Diệp Tông","Hóa Ý Môn","Cửu Quốc Minh"],"nguon":["@c0720"]},{"id":"ngoc-hoa-hien","name":"Ngọc Hòa hiên","capDo":"khac","parentId":"dien-thien-thanh","blurb":"Cửa hàng tạp hóa bình thường ở góc hẻo lánh Điền Thiên Thành, bảng hiệu gỗ đen, bên trong bán phù lục và nguyên liệu. Phía sau kho hàng có cơ quan thế tục dẫn xuống mật thất dưới đất hơn mười trượng, nơi Nam Lũng Hầu và Tuyền Kì Tử ẩn náu.","detail":"Cửa hàng tạp hóa nằm ở góc hẻo lánh Điền Thiên Thành, bảng hiệu gỗ đen ghi Ngọc Hòa hiên. Gian phòng bảy trượng bên trong bán phù lục và nguyên liệu bình thường. Chưởng quỹ là trung niên nhân tu vi Luyện Khí kỳ. Phía sau là kho hàng đầy tủ gỗ, trong đó có cơ quan thế tục (nhấn nút trên tủ, lộ vách tường, giẫm đá mở thông đạo) dẫn xuống mật thất đá dưới lòng đất hơn mười trượng. Cơ quan dùng phương pháp thế tục nhằm tránh bị tu sĩ qua đường cảm ứng cấm chế. Mật thất có tầng bình chướng che linh giác.","theLucLienQuan":["Thiên Cực Môn"],"nguon":["@c0723"]},{"id":"bien-gioi-ngu-quoc","name":"Biên giới Ngu Quốc","capDo":"khac","parentId":"ngu-quoc","blurb":"Khu vực biên giới Ngu Quốc, nơi Cửu Quốc Minh bố trí cấm chế đại trận phòng thủ chống pháp sĩ Mộ Lan.","detail":"Một trong hơn mười nơi trọng yếu có cấm chế đại trận dọc đường tiến quân của pháp sĩ Mộ Lan. Hiện chỉ có một tu sĩ Nguyên Anh tọa trấn, Hàn Lập cùng lão giả họ Mã và Cốc Song Bồ được phái tới trợ giúp.","theLucLienQuan":["Cửu Quốc Minh"],"nguon":["@c0725"]},{"id":"hoang-long-son","name":"Hoàng Long Sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Ngọn núi gần Ngu Quốc, đại bản doanh phòng thủ chống pháp sĩ Mộ Lan, do đại hán họ Lục trấn giữ.","detail":"Ngọn núi gần Ngu Quốc, có quỳnh bàn lầu các và đại sảnh trên đỉnh. Được bảo vệ bởi cấm chế đại trận lục sắc vụ hải bao phủ phạm vi hơn mười dặm. Là nơi Hàn Lập cùng hai Nguyên Anh đồng đạo đến chi viện chuẩn bị đối chiến pháp sĩ Mộ Lan xâm lấn.","theLucLienQuan":[],"nguon":["@c0726","@c0748"]},{"id":"thien-thai-coc","name":"Thiên Thai Cốc","cn":"","capDo":"khac","parentId":"cuu-quoc-minh","blurb":"Cứ điểm của Cửu Quốc Minh đã bị pháp sĩ công phá chiếm được, Bặc đạo hữu thua trận, tu sĩ chiến bại đang tháo chạy về phía cứ điểm hiện tại.","detail":"Một cứ điểm thuộc Cửu Quốc Minh, bị một đội pháp sĩ công phá và chiếm giữ. Trọc mi đại hán thông báo tu sĩ chiến bại sẽ tháo chạy tới cứ điểm của hắn trong nửa ngày.","theLucLienQuan":["Cửu Quốc Minh"],"nguon":["@c0727"]},{"id":"dai-dien-trung-tam-dai-tran-hoang-long-son","name":"Đại điện trung tâm đại trận Hoàng Long Sơn","cn":null,"capDo":"khac","parentId":"hoang-long-son","blurb":"Đại điện nằm trong Hoàng Long Sơn, là trung tâm và nơi cấm chế lợi hại nhất của toàn bộ đại trận.","detail":"Bốn vách tường có thể phát ngân quang hình thành quang tráo (lồng ánh sáng bạc) nhốt mục tiêu, tu sĩ Nguyên Anh dùng pháp bảo tấn công cũng bị bắn ngược. Hai bên có thạch bích ẩn giấu có thể ra vào. Lệnh bài kích hoạt cấm chế sẽ phóng ngân hoa diễm lệ hủy diệt bên trong lồng, đủ sức hình thần câu diệt tu sĩ Nguyên Anh.","theLucLienQuan":[],"nguon":["@c0733"]},{"id":"thao-nguyen-mo-lan","name":"Thảo nguyên Mộ Lan","cn":null,"capDo":"vuc","parentId":null,"blurb":"Quê hương của người Mộ Lan, vùng thảo nguyên rộng lớn nơi các pháp sĩ sinh sống.","detail":"Hơn nửa thảo nguyên đã bị người Đột Ngột chiếm cứ sau khi chủ lực Mộ Lan đại bại trong quyết chiến. Tư nguyên tu luyện (đan dược, linh thạch) thiếu thốn trầm trọng, nhiều pháp sĩ cấp thấp không thể tiến cấp.","theLucLienQuan":[],"nguon":["@c0733"]},{"id":"cuc-tay","name":"Cực tây","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập quyết tâm tới để lấy mấy tầng khẩu quyết cuối cùng của Đại Diễn Quyết sau trận chiến Mộ Lan.","detail":"Hàn Lập nhận ra Đại Diễn Quyết chưa học hoàn toàn nên thần thức thua Nguyên Anh Hậu Kỳ, quyết tâm sau trận chiến sẽ tới cực tây lấy mấy tầng khẩu quyết cuối.","theLucLienQuan":[],"nguon":["@c0743","@c0789"]},{"id":"thach-thanh-thien-nhat","name":"Thạch thành Thiên Nhất","cn":"天一石城","capDo":"thanh","parentId":"bac-luong-quoc","blurb":"Tòa thạch thành do tứ đại thế lực Thiên Nam dùng đại thần thông xây dựng chỉ trong một đêm tại biên giới Bắc Lương Quốc và Ngu Quốc, làm cứ điểm đối kháng quân Mộ Lan.","detail":"Tứ đại thế lực tại Thiên Nam liên thủ, dùng đại thần thông xây dựng tòa thạch thành này chỉ trong một đêm tại biên giới giữa Bắc Lương Quốc và Ngu Quốc. Thạch thành Thiên Nhất trở thành cứ điểm đối kháng chính của tu sĩ Thiên Nam trước đại quân pháp sĩ Mộ Lan. Lữ Lạc cùng tu sĩ cao cấp Thiên Đạo Minh đóng quân tại đây.","theLucLienQuan":["Cửu Quốc Minh","Lạc Vân Tông","Thiên Đạo Minh"],"nguon":["@c0745"]},{"id":"son-coc-nam-thien-nhat-thanh","name":"Sơn cốc ngoài Thiên Nhất thành","capDo":"khac","parentId":"thien-nam","blurb":"Sơn cốc nhỏ cách Thiên Nhất thành vài chục dặm về phía Nam, diện tích hơn trăm trượng, lối vào bị Chướng Nhãn thuật phủ sương trắng. Nơi Mai Ngưng tạm trú.","detail":"Sơn cốc nằm phía Nam Thiên Nhất thành, cách vài chục dặm. Diện tích hơn trăm trượng, bên trong chỉ có mấy gian thạch ốc đơn sơ. Lối vào bị Chướng Nhãn thuật bao phủ sương mù trắng, cần lệnh bài để mở. Nơi Mai Ngưng ẩn cư, được nữ tử họ Tống sắp xếp.","theLucLienQuan":[],"nguon":["@c0748"]},{"id":"dai-tan-quoc","name":"Đại Tấn quốc","capDo":"quoc-gia","parentId":null,"blurb":"Đại đế quốc trong truyền thuyết, diện tích lớn hơn Thiên Nam gấp vài chục lần. Hàn Lập cân nhắc đến đây tìm Canh Tinh và giao hộp xương cho Thiên Phù môn.","detail":"Hàn Lập nghĩ tới Đại Tấn quốc như phương án tìm Canh Tinh nếu Thiên Nam không đủ. Diện tích lớn hơn Thiên Nam gấp vài chục lần, là nơi Thiên Phù môn tọa lạc.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0748"]},{"id":"dai-dien-tu-hoi","name":"Đại điện tụ hội","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Nơi tụ tập các tu sĩ Nguyên Anh Thiên Nam, bố trí đơn giản với một cột đá lớn ở trung tâm và khoảng 16–17 ghế tinh xảo. Tu sĩ Kết Đan trông cửa, cửa bên là lối tam đại tu sĩ bước ra.","detail":"Đại điện nơi diễn ra tụ hội lão quái Nguyên Anh. Bên trong có một cột đá thật lớn ở trung tâm, khoảng 16–17 ghế tinh xảo cách nhau mấy trượng. Tu sĩ ma đạo ngồi phía bên phải, chính đạo chiếm ghế bên trái, Thiên Đạo Minh và Cửu Quốc Minh ngồi tùy ý. Tu sĩ Kết Đan trông cửa chính, cửa bên là lối tam đại tu sĩ Nguyên Anh Hậu Kỳ bước ra.","theLucLienQuan":[],"nguon":["@c0754"]},{"id":"co-truyen-tong-tran","name":"Cổ Truyền Tống Trận","cn":"古传送阵","capDo":"khac","parentId":"thien-nam","blurb":"Trận pháp truyền tống cổ xưa, Hàn Lập từng thông qua trận này đi tới nơi nào đó. Chí Dương thượng nhân nghi hắn đã kế thừa y bát tu sĩ thượng cổ qua trận này.","detail":"Cổ Truyền Tống Trận là trận pháp truyền tống từ thời thượng cổ. Chí Dương thượng nhân nhắc rằng Hàn Lập trước đó đã thông qua trận này đi tới nơi nào đó, nghi rằng hắn kế thừa y bát hoàn chỉnh của tu sĩ thượng cổ.","theLucLienQuan":[],"nguon":["@c0758"]},{"id":"dai-doanh-thien-nam","name":"Đại doanh Thiên Nam","cn":"","capDo":"khac","parentId":"bien-gioi-ngu-quoc","blurb":"Doanh trại lớn của liên minh tu sĩ Thiên Nam tại biên giới Ngu Quốc – Bắc Lương Quốc, bao bọc bởi quang mạc ngũ sắc, có hệ thống cấm chế và trạm tuần tra.","detail":"Phía Nam biên giới, nơi tu sĩ Thiên Nam tập kết chuẩn bị đại chiến với Mộ Lan. Được bao phủ bởi ngũ sắc quang mạc dày đặc, có hệ thống nghiệm chứng thân phận. Chủ sự là Chí Dương Thượng Nhân cùng tam đại tu sĩ.","theLucLienQuan":["Chính Đạo minh"],"nguon":["@c0761"]},{"id":"tu-quoc","name":"Tư quốc","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Quốc gia được tứ đại thế lực hứa cho Thiên Hận Lão Quái để khai tông lập phái, đổi lại nhiệm vụ phá kho tài nguyên Mộ Lan.","detail":"Tư quốc được Long Hàm đại diện tứ đại thế lực cam đoan giao cho Thiên Hận Lão Quái sau khi hoàn thành nhiệm vụ phá hoại kho tài nguyên linh thạch bí mật của Mộ Lan tộc tại Điền Thiên Thành.","theLucLienQuan":[],"nguon":["@c0763"]},{"id":"chien-truong-bien-gioi-thien-nam","name":"Chiến trường biên giới Thiên Nam","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Khu vực biên giới nơi diễn ra đại chiến quy mô lớn giữa tu sĩ Thiên Nam và pháp sĩ Mộ Lan, vô số chiến đoàn lớn nhỏ trên trời dưới đất, bảo khí linh quang chớp động khắp nơi.","detail":"Chiến trường hỗn chiến quy mô lớn, bầu trời và mặt đất đầy bảo khí linh quang chớp động không thôi, vô số chiến đoàn lớn nhỏ giao chiến, chưa phân thắng bại.","theLucLienQuan":["Mộ Lan nhân","Chính Đạo minh"],"nguon":["@c0769"]},{"id":"thien-nhat-thanh","name":"Thiên Nhất Thành","capDo":"thanh","parentId":"thien-nam","blurb":"Căn cứ phía Thiên Nam, nơi Thiên Hận lão quái trốn về báo tin Đột Ngột nhân tấn công Mộ Lan.","detail":"Thành trì thuộc Thiên Nam, đóng vai trò căn cứ trong cuộc chiến biên giới với Mộ Lan. Thiên Hận lão quái trốn về đây xác nhận tin tình báo Đột Ngột nhân.","theLucLienQuan":["Thiên Nam"],"nguon":["@c0780"]},{"id":"tan-quoc","name":"Tấn quốc","capDo":"quoc-gia","parentId":null,"blurb":"Quê hương tông chủ Âm La Tông, nơi có các tông môn liên hợp Đột Ngột nhân tấn công Mộ Lan.","detail":"Quốc gia ngoài Thiên Nam, quê hương của Âm La Tông. Tông môn Tấn quốc liên hợp với Đột Ngột nhân đồng loạt tấn công Mộ Lan nhân.","theLucLienQuan":["Âm La Tông","Đột Ngột nhân"],"nguon":["@c0780"]},{"id":"huyen-thien-phong","name":"Huyền Thiên phong","cn":"玄天峰","capDo":"khac","parentId":null,"blurb":"Địa điểm hắc bào nam tử yêu cầu Hàn Lập mang Kim Lôi Trúc tới gặp mặt.","detail":"Huyền Thiên phong là nơi hắc bào nam tử hẹn gặp Hàn Lập trong ngọc giản đỏ máu, yêu cầu mang theo Kim Lôi Trúc pháp bảo. Vị trí cụ thể chưa rõ.","theLucLienQuan":[],"nguon":["@c0781"]},{"id":"mat-that-lac-van-tong","name":"Mật thất Lạc Vân Tông","cn":"","capDo":"khac","parentId":"lac-van-tong","blurb":"Mật thất nơi Hàn Lập bế quan luyện Canh Tinh vào phi kiếm, cũng là nơi đặt tường băng phong ấn Nam Cung Uyển, đã được Đại trưởng lão liệt vào cấm địa.","detail":"Mật thất nằm trong Lạc Vân Tông, bên trong có tường băng phong ấn Nam Cung Uyển. Đại trưởng lão đã liệt nơi này vào cấm địa, không cho phổ thông đệ tử đến gần. Hàn Lập bế quan tại đây luyện Canh Tinh vào phi kiếm, đồng thời bày thêm pháp trận bảo vệ tường băng.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0782"]},{"id":"tang-thu-cac-lac-van-tong","name":"Tàng thư các Lạc Vân Tông","cn":"","capDo":"khac","parentId":"lac-van-tong","blurb":"Tàng thư các của Lạc Vân Tông, nơi Lữ Lạc đến tìm thượng cổ điển tịch về cách giải Phong Hồn Chú.","detail":"Lữ Lạc đến tàng thư các tìm kiếm thượng cổ điển tịch có ghi chép về phương pháp giải Phong Hồn Chú để giúp Nam Cung Uyển.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0782"]},{"id":"thien-tru-son","name":"Thiên Trụ Sơn","cn":"天柱山","capDo":"khac","parentId":null,"blurb":"Đỉnh núi nơi đặt Truyền Tống Trận đơn sơ và tảng đá khắc chữ dẫn dụ Hàn Lập, hắc bào thanh niên rời đi từ đây.","detail":"Đỉnh núi nơi hắc bào thanh niên để lại Truyền Tống Trận đơn sơ và tảng đá khắc bốn chữ hẹn gặp. Hàn Lập bay tới đây, phát hiện trận và tin nhắn, rồi trang bị phòng thủ tối đa trước khi mạo hiểm bước vào trận bị truyền tống đi xa ngàn dặm.","theLucLienQuan":[],"nguon":["@c0784"]},{"id":"vo-danh-tieu-dao","name":"Vô danh tiểu đảo","cn":"","capDo":"khac","parentId":null,"blurb":"Tiểu đảo giữa hồ nước cách Thiên Trụ Sơn ngàn dặm, nơi hắc bào thanh niên bày sẵn cấm chế Thất long thung chờ đối đầu Hàn Lập.","detail":"Vô danh tiểu đảo giữa hồ nước cách Thiên Trụ Sơn ngàn dặm. Bên bờ ao đầm nước bùn ẩm ướt, có rừng cây nhỏ thấp, mơ hồ nghe tiếng sóng biển. Hắc bào thanh niên đã bày sẵn cấm chế và Thất long thung tại đây, dẫn dụ Hàn Lập qua Truyền Tống Trận đến đối đầu.","theLucLienQuan":[],"nguon":["@c0784"]},{"id":"dai-sa-mac-thien-nam-cuc-tay","name":"Đại sa mạc (Thiên Nam — Cực Tây)","cn":"","capDo":"vuc","parentId":null,"blurb":"Sa mạc hàng ngàn dặm ngăn cách Thiên Nam và Cực Tây, trên không quanh năm thổi cuồng phong mãnh liệt khiến tu sĩ không thể phi độn.","detail":"Đại sa mạc kéo dài hàng ngàn dặm nằm giữa Thiên Nam và Cực Tây. Trên không nhiều năm thổi cuồng phong mãnh liệt, tu sĩ phi độn sẽ bị tiêu hao hết pháp lực, chỉ có cách đi bộ xuyên qua.","theLucLienQuan":[],"nguon":["@c0789"]},{"id":"tu-mau-phong","name":"Tử Mẫu Phong","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Nơi đặt động phủ của Hàn Lập.","detail":"Tử Mẫu Phong là nơi đặt động phủ của Hàn Lập, hắn trở về đây sau khi thăm Nam Cung Uyển trong mật thất băng bích.","theLucLienQuan":[],"nguon":["@c0789"]}]};
